update fit_exercises set image_url = 'https://cdn.muscleandstrength.com/sites/default/files/wide-grip-reverse-bench-press.jpg' where name = 'Wide Reverse Grip Bench Press';
update fit_exercises set image_url = 'https://cdn.muscleandstrength.com/sites/default/files/barbell_wide_stance_squat.jpg' where name = 'Wide Squat';
update fit_exercises set video_url = 'https://www.youtube.com/embed/V3iccY5syPs?rel=0', description = 'The wide stance leg press exercise is a variation of the leg press and an exercise used to build the muscles of the legs. It’ll primarily focus on building the muscles of the quadriceps, but also target the hamstrings, glutes, and calves.', image_url = 'https://cdn.muscleandstrength.com/sites/default/files/wide-stance-leg-press-1.jpg' where name = 'Wide Stance 45 Degree Leg Press';
update fit_exercises set video_url = 'https://www.youtube.com/embed/4roeIJ-zfwM?rel=0', description = 'The Zercher squat is a squat variation and an exercise used to target the muscles of the quad.', image_url = 'https://cdn.muscleandstrength.com/sites/default/files/zercher-squat.jpg' where name = 'Zerchers Squat';
update fit_exercises set video_url = 'https://www.youtube.com/embed/7yPINa6H47o?rel=0', description = 'The Zottman preacher curl is a variation of the Zottman curl and an exercise used to strengthen the muscles of the biceps.', image_url = 'https://cdn.muscleandstrength.com/sites/default/files/zottman-preacher-curl.jpg' where name = 'Zottman Preacher Curl';
update fit_exercises set video_url = 'https://www.youtube.com/embed/tuwHzzPdaGc?rel=0', description = 'The barbell bench press is a classic exercise popular among all weight lifting circles. From bodybuilders to powerlifters, the bench press is a staple chest exercise in nearly every workout program.', image_url = 'https://cdn.muscleandstrength.com/sites/default/files/barbell-bench-press_0.jpg' where name = 'Développé couché barre';
update fit_exercises set video_url = 'https://www.youtube.com/embed/KEFQyLkDYtI?rel=0', description = 'The push up is an exercise used to build the muscles of the chest. The shoulders and triceps will be indirectly involved as well.', image_url = 'https://cdn.muscleandstrength.com/sites/default/files/push-ups.jpg' where name = 'Pompes';
update fit_exercises set description = 'The lying leg curl is an isolation exercise primarily targeting the hamstrings (the muscles at the back of your thighs).', image_url = 'https://cdn.muscleandstrength.com/sites/default/files/lying_leg_curl.jpg' where name = 'Leg curl';
update fit_exercises set video_url = 'https://www.youtube.com/embed/0fl1RRgJ83I?rel=0', description = 'The seated leg extension is an isolation exercise and one used to target the muscles of the quads.', image_url = 'https://cdn.muscleandstrength.com/sites/default/files/leg-extension.jpg' where name = 'Extension jambes';
update fit_exercises set image_url = 'https://cdn.muscleandstrength.com/sites/default/files/standing-barbell-calf-raise.jpg' where name = 'Mollets debout';
update fit_exercises set description = 'The Barbell Upright Row is a compound exercise that primarily targets the shoulders, specifically the lateral deltoids, and the upper traps. It also engages the biceps and forearms.', image_url = 'https://cdn.muscleandstrength.com/sites/default/files/upright-row.jpg' where name = 'Rowing menton';

-- Vérification
select name, video_url is not null as has_video, description is not null as has_desc from fit_exercises order by name;
